import{_ as n,o as a,c as s,ai as o}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Streaming and Chunking","description":"","frontmatter":{"summary":"Streaming + chunking behavior (block replies, draft streaming, limits)","read_when":["Explaining how streaming or chunking works on channels","Changing block streaming or channel chunking behavior","Debugging duplicate/early block replies or draft streaming"],"title":"Streaming and Chunking"},"headers":[],"relativePath":"concepts/streaming.md","filePath":"concepts/streaming.md","lastUpdated":1771906665000}'),t={name:"concepts/streaming.md"};function l(i,e,r,c,d,p){return a(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="streaming-chunking" tabindex="-1"><a class="header-anchor" href="#streaming-chunking">#</a> Streaming + chunking</h1><p>OpenSoul has two separate “streaming” layers:</p><ul><li><strong>Block streaming (channels):</strong> emit completed <strong>blocks</strong> as the assistant writes. These are normal channel messages (not token deltas).</li><li><strong>Token-ish streaming (Telegram only):</strong> update a <strong>draft bubble</strong> with partial text while generating; final message is sent at the end.</li></ul><p>There is <strong>no real token streaming</strong> to external channel messages today. Telegram draft streaming is the only partial-stream surface.</p><h2 id="block-streaming-channel-messages" tabindex="-1"><a class="header-anchor" href="#block-streaming-channel-messages">#</a> Block streaming (channel messages)</h2><p>Block streaming sends assistant output in coarse chunks as it becomes available.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Model output</span></span>
<span class="line"><span>  └─ text_delta/events</span></span>
<span class="line"><span>       ├─ (blockStreamingBreak=text_end)</span></span>
<span class="line"><span>       │    └─ chunker emits blocks as buffer grows</span></span>
<span class="line"><span>       └─ (blockStreamingBreak=message_end)</span></span>
<span class="line"><span>            └─ chunker flushes at message_end</span></span>
<span class="line"><span>                   └─ channel send (block replies)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>Legend:</p><ul><li><code>text_delta/events</code>: model stream events (may be sparse for non-streaming models).</li><li><code>chunker</code>: <code>EmbeddedBlockChunker</code> applying min/max bounds + break preference.</li><li><code>channel send</code>: actual outbound messages (block replies).</li></ul><p><strong>Controls:</strong></p><ul><li><code>agents.defaults.blockStreamingDefault</code>: <code>&quot;on&quot;</code>/<code>&quot;off&quot;</code> (default off).</li><li>Channel overrides: <code>*.blockStreaming</code> (and per-account variants) to force <code>&quot;on&quot;</code>/<code>&quot;off&quot;</code> per channel.</li><li><code>agents.defaults.blockStreamingBreak</code>: <code>&quot;text_end&quot;</code> or <code>&quot;message_end&quot;</code>.</li><li><code>agents.defaults.blockStreamingChunk</code>: <code>{ minChars, maxChars, breakPreference? }</code>.</li><li><code>agents.defaults.blockStreamingCoalesce</code>: <code>{ minChars?, maxChars?, idleMs? }</code> (merge streamed blocks before send).</li><li>Channel hard cap: <code>*.textChunkLimit</code> (e.g., <code>channels.whatsapp.textChunkLimit</code>).</li><li>Channel chunk mode: <code>*.chunkMode</code> (<code>length</code> default, <code>newline</code> splits on blank lines (paragraph boundaries) before length chunking).</li><li>Discord soft cap: <code>channels.discord.maxLinesPerMessage</code> (default 17) splits tall replies to avoid UI clipping.</li></ul><p><strong>Boundary semantics:</strong></p><ul><li><code>text_end</code>: stream blocks as soon as chunker emits; flush on each <code>text_end</code>.</li><li><code>message_end</code>: wait until assistant message finishes, then flush buffered output.</li></ul><p><code>message_end</code> still uses the chunker if the buffered text exceeds <code>maxChars</code>, so it can emit multiple chunks at the end.</p><h2 id="chunking-algorithm-low-high-bounds" tabindex="-1"><a class="header-anchor" href="#chunking-algorithm-low-high-bounds">#</a> Chunking algorithm (low/high bounds)</h2><p>Block chunking is implemented by <code>EmbeddedBlockChunker</code>:</p><ul><li><strong>Low bound:</strong> don’t emit until buffer &gt;= <code>minChars</code> (unless forced).</li><li><strong>High bound:</strong> prefer splits before <code>maxChars</code>; if forced, split at <code>maxChars</code>.</li><li><strong>Break preference:</strong> <code>paragraph</code> → <code>newline</code> → <code>sentence</code> → <code>whitespace</code> → hard break.</li><li><strong>Code fences:</strong> never split inside fences; when forced at <code>maxChars</code>, close + reopen the fence to keep Markdown valid.</li></ul><p><code>maxChars</code> is clamped to the channel <code>textChunkLimit</code>, so you can’t exceed per-channel caps.</p><h2 id="coalescing-merge-streamed-blocks" tabindex="-1"><a class="header-anchor" href="#coalescing-merge-streamed-blocks">#</a> Coalescing (merge streamed blocks)</h2><p>When block streaming is enabled, OpenSoul can <strong>merge consecutive block chunks</strong> before sending them out. This reduces “single-line spam” while still providing progressive output.</p><ul><li>Coalescing waits for <strong>idle gaps</strong> (<code>idleMs</code>) before flushing.</li><li>Buffers are capped by <code>maxChars</code> and will flush if they exceed it.</li><li><code>minChars</code> prevents tiny fragments from sending until enough text accumulates (final flush always sends remaining text).</li><li>Joiner is derived from <code>blockStreamingChunk.breakPreference</code> (<code>paragraph</code> → <code>\\n\\n</code>, <code>newline</code> → <code>\\n</code>, <code>sentence</code> → space).</li><li>Channel overrides are available via <code>*.blockStreamingCoalesce</code> (including per-account configs).</li><li>Default coalesce <code>minChars</code> is bumped to 1500 for Signal/Slack/Discord unless overridden.</li></ul><h2 id="human-like-pacing-between-blocks" tabindex="-1"><a class="header-anchor" href="#human-like-pacing-between-blocks">#</a> Human-like pacing between blocks</h2><p>When block streaming is enabled, you can add a <strong>randomized pause</strong> between block replies (after the first block). This makes multi-bubble responses feel more natural.</p><ul><li>Config: <code>agents.defaults.humanDelay</code> (override per agent via <code>agents.list[].humanDelay</code>).</li><li>Modes: <code>off</code> (default), <code>natural</code> (800–2500ms), <code>custom</code> (<code>minMs</code>/<code>maxMs</code>).</li><li>Applies only to <strong>block replies</strong>, not final replies or tool summaries.</li></ul><h2 id="stream-chunks-or-everything" tabindex="-1"><a class="header-anchor" href="#stream-chunks-or-everything">#</a> “Stream chunks or everything”</h2><p>This maps to:</p><ul><li><strong>Stream chunks:</strong> <code>blockStreamingDefault: &quot;on&quot;</code> + <code>blockStreamingBreak: &quot;text_end&quot;</code> (emit as you go). Non-Telegram channels also need <code>*.blockStreaming: true</code>.</li><li><strong>Stream everything at end:</strong> <code>blockStreamingBreak: &quot;message_end&quot;</code> (flush once, possibly multiple chunks if very long).</li><li><strong>No block streaming:</strong> <code>blockStreamingDefault: &quot;off&quot;</code> (only final reply).</li></ul><p><strong>Channel note:</strong> For non-Telegram channels, block streaming is <strong>off unless</strong><code>*.blockStreaming</code> is explicitly set to <code>true</code>. Telegram can stream drafts (<code>channels.telegram.streamMode</code>) without block replies.</p><p>Config location reminder: the <code>blockStreaming*</code> defaults live under <code>agents.defaults</code>, not the root config.</p><h2 id="telegram-draft-streaming-token-ish" tabindex="-1"><a class="header-anchor" href="#telegram-draft-streaming-token-ish">#</a> Telegram draft streaming (token-ish)</h2><p>Telegram is the only channel with draft streaming:</p><ul><li>Uses Bot API <code>sendMessageDraft</code> in <strong>private chats with topics</strong>.</li><li><code>channels.telegram.streamMode: &quot;partial&quot; | &quot;block&quot; | &quot;off&quot;</code>. <ul><li><code>partial</code>: draft updates with the latest stream text.</li><li><code>block</code>: draft updates in chunked blocks (same chunker rules).</li><li><code>off</code>: no draft streaming.</li></ul></li><li>Draft chunk config (only for <code>streamMode: &quot;block&quot;</code>): <code>channels.telegram.draftChunk</code> (defaults: <code>minChars: 200</code>, <code>maxChars: 800</code>).</li><li>Draft streaming is separate from block streaming; block replies are off by default and only enabled by <code>*.blockStreaming: true</code> on non-Telegram channels.</li><li>Final reply is still a normal message.</li><li><code>/reasoning stream</code> writes reasoning into the draft bubble (Telegram only).</li></ul><p>When draft streaming is active, OpenSoul disables block streaming for that reply to avoid double-streaming.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Telegram (private + topics)</span></span>
<span class="line"><span>  └─ sendMessageDraft (draft bubble)</span></span>
<span class="line"><span>       ├─ streamMode=partial → update latest text</span></span>
<span class="line"><span>       └─ streamMode=block   → chunker updates draft</span></span>
<span class="line"><span>  └─ final reply → normal message</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>Legend:</p><ul><li><code>sendMessageDraft</code>: Telegram draft bubble (not a real message).</li><li><code>final reply</code>: normal Telegram message send.</li></ul>`,36)])])}const m=n(t,[["render",l]]);export{u as __pageData,m as default};
